import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [valid, setValid] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    // TO DO: validate username and password
    setValid(true);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 rounded">
        <form onSubmit={handleSubmit}>
          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="username">Username</label>
            <input className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700" type="text" id="username" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username"/>
          </div>
          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="password">Password</label>
            <input className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700" type="password" id="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password"/>
          </div>
          <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded" type="submit">Submit</button>
        </form>
        {valid && <text className="text-green-500">Credentials are valid!</text>}
      </div>
    </div>
  );
};

export default App;
